]

instance Anemometer : DTDFVocab:SensingComponent [
    base:desc "Anemometer that measures wind speed affecting crane motion",
    producedData WindSpeedDataTransmitted
]

instance ArduinoMotorStateReader : DTDFVocab:SensingComponent [
    base:desc "Arduino firmware reads motor state information (current, position) from cart and hoist stepper motors",
    producedData MotorStateDataTransmitted
]

// C2: Acting components
instance CartStepperMotor : DTDFVocab:ActingComponent [
    base:desc "Cartesian stepper motor that drives the crane carriage along the gantry"
]

instance HoistStepperMotor : DTDFVocab:ActingComponent [
    base:desc "Hoist stepper motor that raises and lowers the electromagnet payload"
]

instance CartMotorController : DTDFVocab:ActingComponent [
    base:desc "Trinamic TMC4671‑Eval controller for the cart stepper motor"
]

instance HoistMotorController : DTDFVocab:ActingComponent [
    base:desc "Trinamic TMC4671‑Eval controller for the hoist stepper motor"
]

instance Electromagnet : DTDFVocab:ActingComponent [
    base:desc "Electromagnet at the end of the hoist used to pick up small pucks (containers)"
]

// C4: Physical‑to‑virtual interaction (DataTransmitted)
instance SwingAngleDataTransmitted : DTDFVocab:DataTransmitted [
    producedFrom SwingAngleEncoder
]

instance WindSpeedDataTransmitted : DTDFVocab:DataTransmitted [
    producedFrom Anemometer
]

instance MotorStateDataTransmitted : DTDFVocab:DataTransmitted [
    producedFrom ArduinoMotorStateReader
]

// C5: Data entities
instance SwingAngleData : DTDFVocab:Data [
    base:desc "Time‑series of swing‑angle measurements (degrees) streamed from the encoder",
    fromData SwingAngleDataTransmitted,
    provides DataLoggingInsight, SystemPerformanceInsight, OptimalTrajectoryInsight, SimulationOutcomeInsight, ValidationAlertInsight
]

instance WindSpeedData : DTDFVocab:Data [
    base:desc "Time‑series of wind speed readings (m/s) streamed from the anemometer",
    fromData WindSpeedDataTransmitted,
    provides DataLoggingInsight, SystemPerformanceInsight, OptimalTrajectoryInsight, SimulationOutcomeInsight, ValidationAlertInsight
]

instance MotorStateData : DTDFVocab:Data [
    base:desc "Time‑series of motor state variables (position, current) for cart and hoist motors",
    fromData MotorStateDataTransmitted,
    provides DataLoggingInsight, SystemPerformanceInsight, OptimalTrajectoryInsight, SimulationOutcomeInsight, ValidationAlertInsight
]

