instance GantryCraneCADModel : DTDFVocab:Model [
    base:desc "Fusion360 CAD model of the lab‑scale gantry crane (frame, motors, electromagnet, shield)"
]

instance KinematicModel : DTDFVocab:Model [
    base:desc "Kinematic model used by the Trajectory Generator and Simulation services to compute feasible motions"
]

// C11: Enablers
instance PhysicalCraneInterface : DTDFVocab:Enabler [
    base:desc "Python program (gantrylib) that reads sensors and commands actuators via the Arduino",
