]

instance MosquittoBroker : DTDFVocab:Enabler [
    base:desc "Eclipse Mosquitto MQTT broker that transports sensor data to all DT services",
    enables DataLoggingService, RealTimeVisualizationService, TrajectoryGenerationService, SimulationService, ContinuousValidationService
]

instance TimescaleDBInstance : DTDFVocab:Enabler [
    base:desc "TimescaleDB time‑series database storing logged measurements for analysis and replay",
    enables DataLoggingService, RealTimeVisualizationService
]

instance GrafanaDashboard : DTDFVocab:Enabler [
    base:desc "Grafana dashboard visualising performance indicators from live sensor data",
    enables RealTimeVisualizationService
]

instance TrajectoryGeneratorEngine : DTDFVocab:Enabler [
    base:desc "Engine that computes optimal motion plans using the kinematic model",
    enables TrajectoryGenerationService
]

instance SimulationEngine : DTDFVocab:Enabler [
    base:desc "Physics‑based simulation service that emulates crane dynamics and controller behaviour",
    enables SimulationService
]

instance ValidationEngine : DTDFVocab:Enabler [
    base:desc "Continuous validation engine that compares executed trajectories with simulated results",
    enables ContinuousValidationService
]

instance DockerComposeOrchestrator : DTDFVocab:Enabler [
    base:desc "Docker‑Compose orchestration of all containerised DT components",
    enables DataLoggingService, RealTimeVisualizationService, TrajectoryGenerationService, SimulationService, ContinuousValidationService
]

// C6: Services
instance DataLoggingService : DTDFVocab:Service [
    base:desc "Service that ingests sensor streams from MQTT and persists them in TimescaleDB",
    provides DataLoggingInsight
]

instance RealTimeVisualizationService : DTDFVocab:Service [
    base:desc "Service that renders live dashboards in Grafana using the latest sensor data",
    provides SystemPerformanceInsight
]

instance TrajectoryGenerationService : DTDFVocab:Service [
    base:desc "Service that generates optimal motion trajectories for the crane using the kinematic model",
    provides OptimalTrajectoryInsight
]

instance SimulationService : DTDFVocab:Service [
    base:desc "Service that runs physics‑based simulations of planned trajectories and controller actions",
    provides SimulationOutcomeInsight
]

instance ContinuousValidationService : DTDFVocab:Service [
    base:desc "Service that continuously validates executed motions against simulated ones and raises alerts",
    provides ValidationAlertInsight, ParameterAdjustmentAction
]

// C17: Insights / Actions
instance DataLoggingInsight : DTDFVocab:Insight [
    base:desc "Confirmation that sensor measurements have been successfully stored in the time‑series database"
]

instance SystemPerformanceInsight : DTDFVocab:Insight [
    base:desc "Key performance indicators (e.g., swing angle, wind speed, motor currents) visualised for operator monitoring"
]

instance OptimalTrajectoryInsight : DTDFVocab:Insight [
    base:desc "Optimal motion plan (position, velocity profiles) computed for the next crane task"
]

instance SimulationOutcomeInsight : DTDFVocab:Insight [
    base:desc "Predicted crane behaviour from the physics simulation (trajectory adherence, energy consumption)"
]

instance ValidationAlertInsight : DTDFVocab:Insight [
    base:desc "Alert generated when discrepancy between executed and simulated trajectories exceeds defined thresholds"
]

instance ParameterAdjustmentAction : DTDFVocab:Action [
    base:desc "Operator‑initiated action to adjust controller gains or trajectory parameters in response to validation alerts",
    IsAutomatic false
]

// C1: Environment (optional grouping)
instance GantryCraneEnvironment : DTDFVocab:Environment [
    base:contains SwingAngleEncoder, Anemometer, ArduinoMotorStateReader,
                 CartStepperMotor, HoistStepperMotor, CartMotorController, HoistMotorController, Electromagnet,
                 PhysicalCraneInterface, LoggingApplication, MosquittoBroker, TimescaleDBInstance,
                 GrafanaDashboard, TrajectoryGeneratorEngine, SimulationEngine, ValidationEngine,
                 DockerComposeOrchestrator,
                 GantryCraneCADModel, KinematicModel
